from collections import defaultdict

def solve(n: int, edges: list[list[int]], label: str) -> int:
    adj = defaultdict(list)
    for u, v in edges:
        adj[u].append(v)
        adj[v].append(u)

    max_len = 0

    def dfs(current, visited, path_labels):
        nonlocal max_len
        if path_labels == path_labels[::-1]:
            max_len = max(max_len, len(path_labels))
        for neighbor in adj[current]:
            if not (visited & (1 << neighbor)):
                new_visited = visited | (1 << neighbor)
                new_path = path_labels + label[neighbor]
                dfs(neighbor, new_visited, new_path)

    for start in range(n):
        visited = 1 << start
        path_labels = label[start]
        dfs(start, visited, path_labels)

    return max_len
